import{_ as e,c as a,o,a1 as s}from"./chunks/framework.DDNAyvCW.js";const d="/assets/aichat.BfYAH7g8.png",m=JSON.parse('{"title":"AI 对话","description":"","frontmatter":{},"headers":[],"relativePath":"docs/ai/dialogs/index.md","filePath":"docs/ai/dialogs/index.md"}'),r={name:"docs/ai/dialogs/index.md"};function i(n,t,l,c,h,p){return o(),a("div",null,t[0]||(t[0]=[s('<h1 id="ai-对话" tabindex="-1">AI 对话 <a class="header-anchor" href="#ai-对话" aria-label="Permalink to &quot;AI 对话&quot;">​</a></h1><p>AI 对话面板是您与 AI 交互的核心枢纽 -- 生成命令、规划复杂任务、自动化多主机操作。</p><p><img src="'+d+'" alt=""></p><h2 id="两种模式-适应各种工作流" tabindex="-1">两种模式，适应各种工作流 <a class="header-anchor" href="#两种模式-适应各种工作流" aria-label="Permalink to &quot;两种模式，适应各种工作流&quot;">​</a></h2><p>Chaterm 提供两种不同的对话模式，每种模式对应不同层级的 AI 参与度。根据您的任务选择合适的模式。</p><h3 id="command-模式" tabindex="-1">Command 模式 <a class="header-anchor" href="#command-模式" aria-label="Permalink to &quot;Command 模式&quot;">​</a></h3><p><strong>AI 为当前活跃终端生成命令 -- 执行前需要您的确认。</strong></p><p>在 Command 模式下，AI 会分析您的请求并生成一条或多条终端命令。每条命令都会展示给您审核，您可以在执行前批准、编辑或拒绝。</p><p><strong>对话示例：</strong></p><blockquote><p><strong>您：</strong> 查找 /var/log 下所有大于 100MB 的日志文件并压缩它们。</p><p><strong>AI：</strong> 以下是查找并压缩这些文件的命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;*.log&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -size</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +100M</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gzip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> {}</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\;</span></span></code></pre></div><p><strong>[批准]</strong> <strong>[拒绝]</strong></p></blockquote><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>在 Command 模式下，命令会在您<strong>当前活跃的终端</strong>中运行。请在批准前确认您连接的是正确的主机。</p></div><hr><h3 id="agent-模式" tabindex="-1">Agent 模式 <a class="header-anchor" href="#agent-模式" aria-label="Permalink to &quot;Agent 模式&quot;">​</a></h3><p><strong>AI 自主执行跨一台或多台主机的多步骤任务。</strong></p><p>Agent 模式赋予 AI 规划、执行、观察结果并自适应调整的能力。它可以通过 <code>@</code> 提及语法在多台主机上操作。AI 会持续工作直到任务完成或需要您的输入。</p><p><strong>对话示例：</strong></p><blockquote><p><strong>您：</strong> @web-server-01 @web-server-02 检查两台主机的磁盘使用情况。如果任何分区使用率超过 80%，查找并列出最大的 10 个文件。</p><p><strong>AI：</strong> 正在 2 台主机上启动任务...</p><p><em>[在 web-server-01 上执行 <code>df -h</code>]</em> -- 所有分区均低于 80%，无需操作。</p><p><em>[在 web-server-02 上执行 <code>df -h</code>]</em> -- <code>/data</code> 使用率为 87%。</p><p><em>[在 web-server-02 上执行 <code>du -ah /data | sort -rh | head -10</code>]</em> -- 以下是最大的 10 个文件...</p></blockquote><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>在 Agent 模式下，在输入框中输入 <code>@</code> 可以查看可用主机列表。您可以选择多台主机进行跨服务器操作。</p></div><hr><h2 id="上传文件和图片" tabindex="-1">上传文件和图片 <a class="header-anchor" href="#上传文件和图片" aria-label="Permalink to &quot;上传文件和图片&quot;">​</a></h2><p>您可以在任何消息中附加文件和图片，为 AI 提供额外的上下文信息。</p><table tabindex="0"><thead><tr><th>类型</th><th>支持的格式</th><th>最大大小</th><th>如何附加</th></tr></thead><tbody><tr><td><strong>图片</strong></td><td><code>.png</code>, <code>.jpg</code>, <code>.jpeg</code>, <code>.webp</code></td><td>5 MB</td><td>拖拽到输入框，或点击上传按钮</td></tr><tr><td><strong>文本/代码文件</strong></td><td><code>.txt</code>, <code>.md</code>, <code>.js</code>, <code>.ts</code>, <code>.py</code>, <code>.java</code>, <code>.cpp</code>, <code>.c</code>, <code>.html</code>, <code>.css</code>, <code>.json</code>, <code>.xml</code>, <code>.yaml</code>, <code>.yml</code>, <code>.sql</code>, <code>.sh</code>, <code>.bat</code>, <code>.ps1</code>, <code>.log</code>, <code>.csv</code>, <code>.tsv</code></td><td>1 MB</td><td>拖拽到输入框，或点击上传按钮</td></tr></tbody></table><p>代码文件会根据其扩展名自动包裹在语法高亮的代码块中。</p><hr><h2 id="历史记录管理" tabindex="-1">历史记录管理 <a class="header-anchor" href="#历史记录管理" aria-label="Permalink to &quot;历史记录管理&quot;">​</a></h2><p>每段对话都会自动保存。您可以回顾、搜索和整理过去的对话。</p><h3 id="查看和恢复历史记录" tabindex="-1">查看和恢复历史记录 <a class="header-anchor" href="#查看和恢复历史记录" aria-label="Permalink to &quot;查看和恢复历史记录&quot;">​</a></h3><ol><li>点击 AI 对话面板左上角的<strong>菜单按钮</strong>。</li><li>使用搜索栏按标题<strong>浏览或搜索</strong>历史记录。</li><li>点击任意历史记录条目即可<strong>恢复</strong>该对话。</li></ol><h3 id="整理历史记录" tabindex="-1">整理历史记录 <a class="header-anchor" href="#整理历史记录" aria-label="Permalink to &quot;整理历史记录&quot;">​</a></h3><ul><li><strong>收藏</strong>对话：点击星标图标 -- 收藏的对话会显示在列表顶部。</li><li><strong>重命名</strong>对话：点击标题并输入新名称。</li><li><strong>删除</strong>对话：点击历史记录条目上的删除图标。</li></ul><p>历史记录支持<strong>分页</strong>功能，即使对话数量很多也能轻松浏览。</p><hr><h2 id="布局切换" tabindex="-1">布局切换 <a class="header-anchor" href="#布局切换" aria-label="Permalink to &quot;布局切换&quot;">​</a></h2><p>Chaterm 提供两种界面布局，让您可以将焦点放在需要的地方。</p><table tabindex="0"><thead><tr><th>布局</th><th>说明</th><th>最佳适用场景</th></tr></thead><tbody><tr><td><strong>Terminal 布局</strong></td><td>终端占据主区域；AI 侧边栏为辅助面板</td><td>以终端为中心的工作流，AI 辅助协作</td></tr><tr><td><strong>Agents 布局</strong></td><td>AI 对话占据主区域；终端为辅助面板</td><td>以 AI 驱动的工作流，终端负责执行</td></tr></tbody></table><p><strong>使用快捷键即时切换布局：</strong></p><ul><li><strong>macOS：</strong> <code>Cmd + E</code></li><li><strong>Windows / Linux：</strong> <code>Ctrl + E</code></li></ul><p>您也可以在 <a href="/docs/settings/general/">通用设置</a> 中更改布局。更改立即生效，无需重启。</p><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/docs/ai/settings/">AI 设置</a> -- 配置提供商、模型和创建新对话</li><li><a href="/docs/ai/preferences/">AI 偏好设置</a> -- 调整推理深度、自动执行和安全策略</li><li><a href="/docs/ai/llms/">模型配置</a> -- 添加和管理 AI 模型提供商</li></ul>',41)]))}const k=e(r,[["render",i]]);export{m as __pageData,k as default};
